/* ============================================================
   UMBLER DESIGN SYSTEM — TOKENS
   Fonte única dos tokens da marca (cores, tipografia, espaçamento,
   radius, sombras, motion, layout) + tokens semânticos adaptativos
   light/dark.

   Migrado 1:1 de umbler-design-system.vercel.app

   COMO USAR EM OUTRO PROJETO (Tailwind v4):
     No CSS de entrada do seu projeto, importe DEPOIS do tailwind:

       @import 'tailwindcss';
       @import '@umbler/ui/tokens.css';   // via pacote npm
       // — ou, se copiado via shadcn —
       @import './tokens.css';

   IMPORTANTE: precisa ser importado em tempo de build (o @theme é uma
   diretiva do Tailwind v4). Um <link> CDN em runtime NÃO processa @theme.
   ============================================================ */

@theme {
  /* -------- Brand — Umbler Blue -------- */
  --color-brand-50: #ebf1ff;
  --color-brand-100: #d0dfff;
  --color-brand-200: #a3c0ff;
  --color-brand-300: #6b99ff;
  --color-brand-400: #3d74ff;
  --color-brand-500: #1a5cff;
  --color-brand-600: #0044d9;
  --color-brand-700: #0033b0;
  --color-brand-800: #002488;
  --color-brand-900: #001866;

  /* -------- Neutral — Surface & Background -------- */
  --color-neutral-50: #f4f5fa;
  --color-neutral-100: #e8eaf2;
  --color-neutral-200: #c4cae0;
  --color-neutral-300: #959fbf;
  --color-neutral-400: #6e7799;
  --color-neutral-500: #4a5278;
  --color-neutral-600: #2a3356;
  --color-neutral-700: #1a2240;
  --color-neutral-800: #111733;
  --color-neutral-900: #0a0f20;
  --color-neutral-950: #030614;

  /* -------- Semantic — Success -------- */
  --color-success-50: #e8fce8;
  --color-success-100: #d0f5d0;
  --color-success-300: #9cd99c;
  --color-success-500: #5cb85c;
  --color-success-600: #438c43;
  --color-success-900: #316631;

  /* -------- Semantic — Warning -------- */
  --color-warning-50: #fffaeb;
  --color-warning-100: #faf1d4;
  --color-warning-300: #f5df9f;
  --color-warning-500: #f2c94e;
  --color-warning-600: #bf9d36;
  --color-warning-900: #a6882e;

  /* -------- Semantic — Error / Danger -------- */
  --color-error-50: #fff1f0;
  --color-error-100: #fad7d4;
  --color-error-300: #f29c96;
  --color-error-500: #f2594e;
  --color-error-600: #c24036;
  --color-error-900: #9c2f27;

  /* -------- Semantic — Info (matches brand) -------- */
  --color-info-50: #ebf1ff;
  --color-info-100: #d0dfff;
  --color-info-300: #6b99ff;
  --color-info-500: #1a5cff;
  --color-info-600: #0044d9;
  --color-info-900: #001866;

  /* -------- Typography -------- */
  --font-sans: 'Inter', ui-sans-serif, system-ui, -apple-system, sans-serif;
  --font-heading: 'p22-mackinac-pro', Georgia, serif;
  --font-mono: 'JetBrains Mono', ui-monospace, 'SF Mono', Menlo, monospace;

  --text-display: 3.5rem;                  /* 56px — destaque de seção */
  --text-display--line-height: 1.05;
  --text-display--font-weight: 500;
  --text-display--letter-spacing: -0.1rem;

  --text-display-lg: 4.5rem;               /* 72px — hero padrão */
  --text-display-lg--line-height: 1.05;
  --text-display-lg--font-weight: 500;
  --text-display-lg--letter-spacing: -0.15rem;

  --text-display-xl: 6rem;                 /* 96px — splash */
  --text-display-xl--line-height: 1.0;
  --text-display-xl--font-weight: 500;
  --text-display-xl--letter-spacing: -0.2rem;

  --text-display-2xl: 8rem;                /* 128px — impacto máximo */
  --text-display-2xl--line-height: 0.95;
  --text-display-2xl--font-weight: 500;
  --text-display-2xl--letter-spacing: -0.4rem;

  --text-h1: 3rem;                         /* 48px */
  --text-h1--line-height: 1.1;
  --text-h1--font-weight: 500;
  --text-h1--letter-spacing: -0.1rem;

  --text-h2: 2.25rem;                      /* 36px */
  --text-h2--line-height: 1.2;
  --text-h2--font-weight: 500;
  --text-h2--letter-spacing: -0.05rem;

  --text-h3: 1.75rem;         /* 28px */
  --text-h3--line-height: 1.25;
  --text-h3--font-weight: 500;

  --text-h4: 1.375rem;        /* 22px */
  --text-h4--line-height: 1.35;
  --text-h4--font-weight: 500;

  --text-body-lg: 1.125rem;   /* 18px */
  --text-body-lg--line-height: 1.6;

  --text-body: 1rem;          /* 16px */
  --text-body--line-height: 1.6;

  --text-body-sm: 0.875rem;   /* 14px */
  --text-body-sm--line-height: 1.5;

  --text-caption: 0.75rem;    /* 12px */
  --text-caption--line-height: 1.4;
  --text-caption--font-weight: 500;

  /* -------- Spacing (4px base) -------- */
  --spacing-0-5: 0.125rem;    /* 2px  — micro */
  --spacing-1:   0.25rem;     /* 4px  — micro */
  --spacing-1-5: 0.375rem;    /* 6px  — micro */
  --spacing-2:   0.5rem;      /* 8px  — componente */
  --spacing-3:   0.75rem;     /* 12px — componente */
  --spacing-4:   1rem;        /* 16px — componente */
  --spacing-5:   1.25rem;     /* 20px — componente */
  --spacing-6:   1.5rem;      /* 24px — componente */
  --spacing-8:   2rem;        /* 32px — seção */
  --spacing-12:  3rem;        /* 48px — seção */

  /* -------- Radius -------- */
  --radius-sm: 0.375rem;      /* 6px */
  --radius-md: 0.625rem;      /* 10px */
  --radius-lg: 1rem;          /* 16px */
  --radius-xl: 1.5rem;        /* 24px */
  --radius-full: 9999px;

  /* -------- Motion -------- */
  --duration-instant: 80ms;     /* feedback tátil — active press */
  --duration-fast: 150ms;
  --duration-normal: 250ms;
  --duration-slow: 400ms;
  --duration-slower: 600ms;

  --ease-out: cubic-bezier(0.22, 1, 0.36, 1);
  --ease-in: cubic-bezier(0.55, 0, 0.78, 0);
  --ease-in-out: cubic-bezier(0.45, 0, 0.55, 1);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);

  /* -------- Loader (gradiente da marca) -------- */
  --color-loader-a: #8bbcf8;    /* azul claro */
  --color-loader-b: #f8c4b8;    /* salmão */

  /* -------- Layout -------- */
  --container-max: 1200px;
  --grid-gutter: 1.5rem;       /* 24px */
  --grid-margin: 2rem;         /* 32px */

  /* -------- Breakpoints -------- */
  --breakpoint-sm: 640px;
  --breakpoint-md: 768px;
  --breakpoint-lg: 1024px;
  --breakpoint-xl: 1280px;
}

/* ============================================================
   TOKENS SEMÂNTICOS ADAPTATIVOS
   Mapeiam para custom properties que mudam entre light/dark.
   Geram utilitários: bg-surface, text-foreground, shadow-md, etc.
   ============================================================ */

@theme inline {
  --color-surface:               var(--surface);
  --color-border:                var(--border);
  --color-border-strong:         var(--border-strong);
  --color-foreground:            var(--foreground);
  --color-foreground-secondary:  var(--foreground-secondary);
  --color-foreground-muted:      var(--foreground-muted);
  --color-foreground-subtle:     var(--foreground-subtle);
  --color-control-track:         var(--control-track);
  --color-control-hover:         var(--control-hover);
  --color-tooltip-bg:            var(--tooltip-bg);
  --color-tooltip-fg:            var(--tooltip-fg);

  --shadow-xs:   var(--shadow-xs-val);
  --shadow-sm:   var(--shadow-sm-val);
  --shadow-md:   var(--shadow-md-val);
  --shadow-lg:   var(--shadow-lg-val);
  --shadow-xl:   var(--shadow-xl-val);
  --shadow-glow: var(--shadow-glow-val);
}

/* Light mode (padrão) */
:root {
  --gradient-brand: #1a5cff;
  --logo-show-light: block;
  --logo-show-dark: none;

  --surface:              #ffffff;
  --border:               rgba(42, 51, 86, 0.18);
  --border-strong:        rgba(42, 51, 86, 0.35);
  --foreground:           #111733;          /* neutral-800 */
  --foreground-secondary: #1a2240;          /* neutral-700 */
  --foreground-muted:     #4a5278;          /* neutral-500 */
  --foreground-subtle:    #6e7799;          /* neutral-400 */
  --control-track:        #c4cae0;          /* neutral-200 */
  --control-hover:        rgba(42, 51, 86, 0.08);  /* hover sutil em controles */

  /* Tooltip — sempre inverso à superfície para contraste máximo */
  --tooltip-bg: #030614;                    /* neutral-950 */
  --tooltip-fg: #ffffff;

  /* Shadows — neutral-500 (rgb 74 82 120), índigo-ardósia, superfícies claras */
  --shadow-xs-val:   0 1px 2px 0 rgb(74 82 120 / 0.14);
  --shadow-sm-val:   0 1px 3px 0 rgb(74 82 120 / 0.16), 0 1px 2px -1px rgb(74 82 120 / 0.14);
  --shadow-md-val:   0 4px 6px -1px rgb(74 82 120 / 0.18), 0 2px 4px -2px rgb(74 82 120 / 0.16);
  --shadow-lg-val:   0 10px 15px -3px rgb(74 82 120 / 0.2), 0 4px 6px -4px rgb(74 82 120 / 0.18);
  --shadow-xl-val:   0 20px 25px -5px rgb(74 82 120 / 0.22), 0 8px 10px -6px rgb(74 82 120 / 0.18);
  --shadow-glow-val: 0 0 32px 0 rgb(26 92 255 / 0.35);
}

/* Dark mode */
.dark {
  --gradient-brand: linear-gradient(90deg, #8bbcf8 0%, #f8c4b8 100%);
  --logo-show-light: none;
  --logo-show-dark: block;

  --surface:              #0a0f20;          /* neutral-900 */
  --border:               rgba(42, 51, 86, 0.7);
  --border-strong:        #4a5278;          /* neutral-500 */
  --foreground:           #e8eaf2;          /* neutral-100 */
  --foreground-secondary: #c4cae0;          /* neutral-200 */
  --foreground-muted:     #6e7799;          /* neutral-400 */
  --foreground-subtle:    #4a5278;          /* neutral-500 */
  --control-track:        #1a2240;          /* neutral-700 */
  --control-hover:        rgba(26, 34, 64, 0.6);   /* neutral-700 @ 60% */

  /* Tooltip — inverso à superfície (claro sobre dark) */
  --tooltip-bg: #ffffff;
  --tooltip-fg: #0a0f20;                    /* neutral-900 */

  /* Shadows — neutral-900 (rgb 10 15 32), superfícies escuras */
  --shadow-xs-val:   0 1px 2px 0 rgb(10 15 32 / 0.3);
  --shadow-sm-val:   0 1px 3px 0 rgb(10 15 32 / 0.35), 0 1px 2px -1px rgb(10 15 32 / 0.3);
  --shadow-md-val:   0 4px 6px -1px rgb(10 15 32 / 0.4), 0 2px 4px -2px rgb(10 15 32 / 0.35);
  --shadow-lg-val:   0 10px 15px -3px rgb(10 15 32 / 0.45), 0 4px 6px -4px rgb(10 15 32 / 0.4);
  --shadow-xl-val:   0 20px 25px -5px rgb(10 15 32 / 0.5), 0 8px 10px -6px rgb(10 15 32 / 0.4);
  --shadow-glow-val: 0 0 32px 0 rgb(26 92 255 / 0.35);
}

/* ============================================================
   BASE TYPOGRAPHY
   ============================================================ */
html {
  font-family: var(--font-sans);
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-heading);
  font-weight: 500;
}

h2 {
  letter-spacing: var(--text-h2--letter-spacing);
}

code,
pre,
kbd {
  font-family: var(--font-mono);
}

/* ============================================================
   CARD AURORA — animação do blob (usada por card-aurora)
   ============================================================ */
@keyframes aurora-spin {
  from { transform: translate(-50%, -50%) rotate(0deg); }
  to   { transform: translate(-50%, -50%) rotate(360deg); }
}

/* ============================================================
   TOOLTIP — fade + scale + slide direcional
   O slide segue o lado em que o tooltip abre (data-side do Radix):
     side=top    → tooltip desliza pra cima ao aparecer
     side=bottom → desliza pra baixo
     side=left   → desliza pra esquerda
     side=right  → desliza pra direita
   ============================================================ */
@keyframes tooltip-from-bottom {
  from { opacity: 0; transform: scale(0.95) translateY(6px); }
  to   { opacity: 1; transform: scale(1)    translateY(0);   }
}
@keyframes tooltip-from-top {
  from { opacity: 0; transform: scale(0.95) translateY(-6px); }
  to   { opacity: 1; transform: scale(1)    translateY(0);    }
}
@keyframes tooltip-from-right {
  from { opacity: 0; transform: scale(0.95) translateX(6px); }
  to   { opacity: 1; transform: scale(1)    translateX(0);   }
}
@keyframes tooltip-from-left {
  from { opacity: 0; transform: scale(0.95) translateX(-6px); }
  to   { opacity: 1; transform: scale(1)    translateX(0);    }
}

/*
 * @utility registra como utilidade Tailwind real — necessário para que
 * variantes compostas (data-[side=top]:data-[state=delayed-open]:...)
 * funcionem no JIT do Tailwind v4.
 */
@utility animate-tooltip-from-bottom {
  animation: tooltip-from-bottom var(--duration-fast) var(--ease-out) forwards;
}
@utility animate-tooltip-from-top {
  animation: tooltip-from-top var(--duration-fast) var(--ease-out) forwards;
}
@utility animate-tooltip-from-right {
  animation: tooltip-from-right var(--duration-fast) var(--ease-out) forwards;
}
@utility animate-tooltip-from-left {
  animation: tooltip-from-left var(--duration-fast) var(--ease-out) forwards;
}

/* ============================================================
   ALERT — slide de cima + fade na montagem
   ============================================================ */
@keyframes alert-in {
  from { opacity: 0; transform: translateY(-6px); }
  to   { opacity: 1; transform: translateY(0); }
}
@utility animate-alert-in {
  animation: alert-in var(--duration-slow) var(--ease-out) both;
}

/* ============================================================
   TAB — pop suave ao ativar (ease-spring, uma vez)
   ============================================================ */
@keyframes tab-pop {
  from { opacity: 0.5; transform: scale(0.94); }
  to   { opacity: 1;   transform: scale(1); }
}
@utility animate-tab-pop {
  animation: tab-pop var(--duration-normal) var(--ease-spring) forwards;
}

/* ============================================================
   DIALOG — open: slide de baixo + fade
   ============================================================ */
@keyframes dialog-in {
  from { opacity: 0; transform: scale(0.97) translateY(10px); }
  to   { opacity: 1; transform: scale(1)    translateY(0); }
}
@keyframes dialog-out {
  from { opacity: 1; transform: scale(1)    translateY(0); }
  to   { opacity: 0; transform: scale(0.97) translateY(6px); }
}
@utility animate-dialog-in {
  animation: dialog-in var(--duration-normal) var(--ease-out) forwards;
}
@utility animate-dialog-out {
  animation: dialog-out var(--duration-fast) var(--ease-in) forwards;
}

/* ============================================================
   EYEBROW / CAPTION — gradiente da marca (padrão DS)
   ============================================================ */
.eyebrow {
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  background: var(--gradient-brand);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  color: transparent;
}
